import{_ as a,o as t,c as r,ag as i}from"./chunks/framework.BLeoozAw.js";const o="/Awesome-SRC-experience/img/640.png",s="/Awesome-SRC-experience/img/%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20241105232010.png",_=JSON.parse('{"title":"SMS Bomb: Logic Flaw in WeChat Mini-Program","description":"How a bypass in the standard login flow allowed for unrestricted SMS message delivery.","frontmatter":{"title":"SMS Bomb: Logic Flaw in WeChat Mini-Program","description":"How a bypass in the standard login flow allowed for unrestricted SMS message delivery.","category":"Logic Flaw","difficulty":"Easy","tags":["SMS-Bomb","WeChat","Mini-Program","Rate-Limiting"],"author":"Community Contributor","date":"2026-04-06","target_type":"web"},"headers":[],"relativePath":"experience/web/sms-verification/sms-logic-flaw.md","filePath":"experience/web/sms-verification/sms-logic-flaw.md"}'),n={name:"experience/web/sms-verification/sms-logic-flaw.md"};function l(c,e,m,g,h,d){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="🛡️-微信小程序逻辑漏洞-绕过限制实现-短信轰炸" tabindex="-1">🛡️ 微信小程序逻辑漏洞：绕过限制实现“短信轰炸” <a class="header-anchor" href="#🛡️-微信小程序逻辑漏洞-绕过限制实现-短信轰炸" aria-label="Permalink to &quot;🛡️ 微信小程序逻辑漏洞：绕过限制实现“短信轰炸”&quot;">​</a></h1><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><strong>漏洞核心</strong>: 业务逻辑分支不一致。系统在“微信一键登录”流程中设置了频率限制，但在“手机号/其他方式登录”的可选分支中，由于缺少图形验证码深度校验或会话绑定缺失，导致限制被绕过。</p></div><h2 id="漏洞产生点" tabindex="-1">漏洞产生点 <a class="header-anchor" href="#漏洞产生点" aria-label="Permalink to &quot;漏洞产生点&quot;">​</a></h2><p><strong>资产</strong>: 某知名品牌微信小程序登录页面。</p><h2 id="攻击链分析-寻找防御缺口" tabindex="-1">攻击链分析：寻找防御缺口 <a class="header-anchor" href="#攻击链分析-寻找防御缺口" aria-label="Permalink to &quot;攻击链分析：寻找防御缺口&quot;">​</a></h2><h3 id="_1-正常业务流-受限" tabindex="-1">1. 正常业务流 (受限) <a class="header-anchor" href="#_1-正常业务流-受限" aria-label="Permalink to &quot;1. 正常业务流 (受限)&quot;">​</a></h3><p>用户进入登录页 -&gt; 授权手机号 -&gt; 服务端校验频率 -&gt; 发送短信。此流程中，服务端对频率有严格监控。</p><h3 id="_2-漏洞绕过流-无限制" tabindex="-1">2. 漏洞绕过流 (无限制) <a class="header-anchor" href="#_2-漏洞绕过流-无限制" aria-label="Permalink to &quot;2. 漏洞绕过流 (无限制)&quot;">​</a></h3><p>用户进入登录页 -&gt; <strong>拒绝</strong>授权手机号 -&gt; 点击“使用其他手机号登录” -&gt; 输入目标手机号 -&gt; 手动触发短信发送。</p><p>由于“手动输入”分支的图形验证码校验逻辑与短信发送逻辑未进行强关联，通过重放请求，可以实现对任意手机号的批量短信冲击。</p><h2 id="实战复盘" tabindex="-1">实战复盘 <a class="header-anchor" href="#实战复盘" aria-label="Permalink to &quot;实战复盘&quot;">​</a></h2><p><img src="'+o+'" alt=""><em>图 1: 手动输入手机号的入口，防护层级显著低于一键授权。</em></p><p><img src="'+s+'" alt=""><em>图 2-4: 演示了通过不同手机号或重发请求实现的批量发送效果。</em></p><h2 id="💡-修复建议" tabindex="-1">💡 修复建议 <a class="header-anchor" href="#💡-修复建议" aria-label="Permalink to &quot;💡 修复建议&quot;">​</a></h2><ul><li><strong>统一鉴权网关</strong>: 确保所有登录分支（一键登录、手动登录、验证码登录）共享同一个<strong>速率限制器（Rate Limiter）</strong>。</li><li><strong>验证码强绑定</strong>: 短信发送请求必须携带通过校验的图形验证码 Token，且该 Token 必须与当前 Session 绑定。</li><li><strong>指纹限制</strong>: 除了手机号维度，还应增加对 IP、设备指纹等维度的多重频率控制。</li></ul><hr><p><em>参考来源: <a href="https://mp.weixin.qq.com/s/8mgOzhc2PeQPAuXrT5vY8Q" target="_blank" rel="noreferrer">微信公众号文章</a></em></p>',17)])])}const u=a(n,[["render",l]]);export{_ as __pageData,u as default};
